const items = $input.all();
const candidates = [];

// Get the data array
const dataArray = items[0].json.data || [];

for (const d of dataArray) {
  // Data is inside "text" field as string
  const textContent = d.text || '';

  if (!textContent) continue;

  let parsed;

  try {
    // Remove ```json and ``` markers
    const cleaned = textContent
      .replace(/```json\n/g, '')
      .replace(/```/g, '')
      .trim();

    // Parse the JSON string
    parsed = JSON.parse(cleaned);

  } catch(e) {
    console.log('Parse error for:', textContent);
    continue;
  }

  if (!parsed || !parsed.candidate_name) continue;

  const matchScore = Number(parsed.match_score) || 0;
  const interestScore = Number(parsed.interest_score) || 0;
  const finalScore = Math.round(
    (matchScore * 0.6) + (interestScore * 0.4)
  );

  candidates.push({
    rank: 0,
    candidate_name: parsed.candidate_name || '',
    candidate_email: parsed.candidate_email || '',
    match_score: matchScore,
    interest_score: interestScore,
    final_score: finalScore,
    interest_level: parsed.interest_level || 'Low',
    match_explanation: parsed.match_explanation || '',
    interest_explanation: parsed.interest_explanation || '',
    outreach_message: parsed.outreach_message || '',
    candidate_reply: parsed.candidate_reply || ''
  });
}

// Check if empty
if (candidates.length === 0) {
  return [{
    json: {
      error: "No candidates found",
      raw: JSON.stringify(items[0].json)
    }
  }];
}

// Sort highest to lowest
candidates.sort((a, b) => 
  b.final_score - a.final_score
);

// Add ranks
for (let i = 0; i < candidates.length; i++) {
  candidates[i].rank = i + 1;
}

return candidates.map(c => ({ json: c }));
